# Minimal usage policy enforcement for an agentic AI system
from __future__ import annotations
import time
from dataclasses import dataclass, field
from enum import Enum
from typing import Any, Callable, Optional


class PolicyEffect(str, Enum):
    ALLOW = "allow"
    DENY = "deny"
    RATE_LIMITED = "rate_limited"
    QUOTA_EXCEEDED = "quota_exceeded"


@dataclass
class PolicyDecision:
    effect: PolicyEffect
    rule_id: str
    message: str
    actor: str
    resource: str


class PolicyViolationError(Exception):
    def __init__(self, decision: PolicyDecision):
        self.decision = decision
        super().__init__(f"Policy violation [{decision.rule_id}]: {decision.message}")


@dataclass
class UsagePolicy:
    allowed_tools: set[str] = field(default_factory=set)
    session_token_quota: int = 0       # 0 = unlimited
    calls_per_minute: int = 0          # 0 = unlimited
    role_tool_grants: dict[str, set[str]] = field(default_factory=dict)


class PolicyEnforcementPoint:
    def __init__(self, policy: UsagePolicy):
        self._policy = policy
        self._counters: dict[str, Any] = {}
        self._violations: list[PolicyDecision] = []

    def _allowed_tools(self, role: str) -> set[str]:
        return self._policy.allowed_tools | self._policy.role_tool_grants.get(role, set())

    def _deny(self, rule_id: str, msg: str, actor: str, resource: str) -> PolicyDecision:
        d = PolicyDecision(PolicyEffect.DENY, rule_id, msg, actor, resource)
        self._violations.append(d)
        return d

    def check_tool(self, actor: str, role: str, tool: str) -> PolicyDecision:
        if tool not in self._allowed_tools(role):
            return self._deny("SCOPE-001", f"Tool '{tool}' not permitted for role '{role}'.", actor, tool)
        return PolicyDecision(PolicyEffect.ALLOW, "SCOPE-001", "ok", actor, tool)

    def check_rate(self, actor: str) -> PolicyDecision:
        if not self._policy.calls_per_minute:
            return PolicyDecision(PolicyEffect.ALLOW, "RATE-001", "unlimited", actor, "")
        key = f"rate:{actor}:{int(time.time() // 60)}"
        count = self._counters.get(key, 0)
        if count >= self._policy.calls_per_minute:
            return self._deny("RATE-001", f"Rate limit {self._policy.calls_per_minute}/min exceeded.", actor, "llm")
        self._counters[key] = count + 1
        return PolicyDecision(PolicyEffect.ALLOW, "RATE-001", "ok", actor, "")

    def check_quota(self, session_id: str, tokens: int, actor: str) -> PolicyDecision:
        if not self._policy.session_token_quota:
            return PolicyDecision(PolicyEffect.ALLOW, "QUOTA-001", "unlimited", actor, "llm")
        key = f"tokens:{session_id}"
        used = self._counters.get(key, 0)
        if used + tokens > self._policy.session_token_quota:
            return self._deny("QUOTA-001", f"Token quota {self._policy.session_token_quota} exceeded.", actor, "llm")
        self._counters[key] = used + tokens
        return PolicyDecision(PolicyEffect.ALLOW, "QUOTA-001", "ok", actor, "llm")

    def call_tool(self, actor: str, role: str, session_id: str,
                  tool_name: str, tool_fn: Callable, **kwargs) -> Any:
        for check in (self.check_tool(actor, role, tool_name), self.check_rate(actor)):
            if check.effect != PolicyEffect.ALLOW:
                raise PolicyViolationError(check)
        return tool_fn(**kwargs)

    @property
    def violations(self) -> list[PolicyDecision]:
        return list(self._violations)


# --- Demo ---
if __name__ == "__main__":
    policy = UsagePolicy(
        allowed_tools={"web_search", "summarize_document"},
        session_token_quota=5000,
        calls_per_minute=10,
        role_tool_grants={"admin": {"send_email"}},
    )
    pep = PolicyEnforcementPoint(policy)

    def web_search(query: str) -> str:
        return f"Results for: {query}"

    def send_email(to: str, body: str) -> str:
        return f"Sent to {to}"

    # Allowed call
    try:
        print(pep.call_tool("alice", "analyst", "s1", "web_search", web_search, query="AI governance"))
    except PolicyViolationError as e:
        print(f"BLOCKED: {e}")

    # Blocked: send_email not in analyst allowlist
    try:
        pep.call_tool("alice", "analyst", "s1", "send_email", send_email, to="x@y.com", body="Hi")
    except PolicyViolationError as e:
        print(f"BLOCKED: {e}")

    # Allowed: admin has send_email grant
    try:
        print(pep.call_tool("carol", "admin", "s2", "send_email", send_email, to="team@y.com", body="Report"))
    except PolicyViolationError as e:
        print(f"BLOCKED: {e}")

    print(f"Violations: {[v.rule_id for v in pep.violations]}")

# Declarative policy: rules expressed as data, evaluated by a generic engine.
# Swap the POLICY dict without touching enforcement code.
import re
import time
from dataclasses import dataclass

POLICY = {
    "version": "2.1.0",
    "tool_allowlist": ["web_search", "summarize_document", "read_database", "delete_record"],
    "rules": [
        {
            "id": "SCOPE-001",
            "condition": {"type": "tool_not_in_allowlist"},
            "effect": "deny",
            "message": "Tool not in policy allowlist.",
        },
        {
            "id": "SCOPE-002",
            "condition": {"type": "tool_requires_role", "tool": "delete_record", "required_role": "admin"},
            "effect": "deny",
            "message": "delete_record requires admin role.",
        },
        {
            "id": "QUOTA-001",
            "condition": {"type": "token_quota_exceeded", "limit": 8000},
            "effect": "deny",
            "message": "Session token quota exhausted.",
        },
        {
            "id": "CONTENT-001",
            "condition": {"type": "output_matches_pattern", "pattern": r"\b(?:\d[ -]?){13,16}\b"},
            "effect": "redact",
            "message": "Potential credit card number redacted.",
        },
    ],
}


@dataclass
class AuthContext:
    actor: str
    role: str
    session_id: str
    tokens_used: int = 0


class DeclarativePolicyEngine:
    """Evaluates a declarative policy against an auth context. First deny wins."""

    def __init__(self, policy: dict):
        self._p = policy

    def check_tool(self, ctx: AuthContext, tool: str) -> tuple[str, str, str]:
        for rule in self._p["rules"]:
            cond = rule["condition"]
            ct = cond["type"]
            matched = False
            if ct == "tool_not_in_allowlist":
                matched = tool not in self._p["tool_allowlist"]
            elif ct == "tool_requires_role":
                matched = tool == cond["tool"] and ctx.role != cond["required_role"]
            elif ct == "token_quota_exceeded":
                matched = ctx.tokens_used >= cond["limit"]
            if matched and rule["effect"] == "deny":
                return "deny", rule["id"], rule["message"]
        return "allow", "", "permitted"

    def check_output(self, text: str) -> tuple[str, str, str]:
        for rule in self._p["rules"]:
            cond = rule["condition"]
            if cond["type"] == "output_matches_pattern":
                if re.search(cond["pattern"], text):
                    return rule["effect"], rule["id"], rule["message"]
        return "allow", "", "clean"


# --- Demo ---
if __name__ == "__main__":
    engine = DeclarativePolicyEngine(POLICY)

    cases = [
        (AuthContext("bob", "analyst", "s1"), "web_search"),
        (AuthContext("bob", "analyst", "s1"), "delete_record"),  # deny: SCOPE-002
        (AuthContext("carol", "admin",   "s2"), "delete_record"),  # allow
        (AuthContext("bob", "analyst", "s1"), "send_email"),     # deny: SCOPE-001
    ]
    for ctx, tool in cases:
        effect, rule_id, msg = engine.check_tool(ctx, tool)
        label = "ALLOW" if effect == "allow" else f"DENY [{rule_id}]"
        print(f"{ctx.actor} ({ctx.role}) -> {tool}: {label}")
        if effect != "allow":
            print(f"  {msg}")

    raw = "Card: 4111 1111 1111 1111 processed."
    eff, rid, msg = engine.check_output(raw)
    print(f"\nOutput check: {eff.upper()} [{rid}] — {msg}")

# MiFID II-compliant usage policy for a financial AI assistant
import hashlib
import uuid
from dataclasses import dataclass, field, asdict
from datetime import date, datetime, timezone

FINANCIAL_POLICY = {
    "version": "1.0.0",
    "deployment": "mifid2-rm-assistant",
    "tool_allowlist": {"get_account_summary", "draft_email", "book_meeting"},
    "daily_token_budget": 20_000,
    "prohibited_phrases": ["guaranteed return", "risk-free", "definitely will increase"],
    "required_disclaimer": "past performance",
}


@dataclass
class AuditRecord:
    event_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    timestamp: str = field(default_factory=lambda: datetime.now(timezone.utc).isoformat())
    actor: str = ""
    client_ref: str = ""
    tool: str = ""
    content_hash: str = ""   # SHA-256; store hash not PHI
    tokens: int = 0
    policy_version: str = ""
    decision: str = ""        # allow / deny
    rule_id: str = ""


class FinancialPolicyEnforcer:
    def __init__(self, policy: dict):
        self._p = policy
        self._token_counts: dict[str, int] = {}
        self._log: list[dict] = []

    def _today_key(self, actor: str) -> str:
        return f"{actor}:{date.today().isoformat()}"

    def check_tool(self, actor: str, tool: str) -> None:
        if tool not in self._p["tool_allowlist"]:
            raise PermissionError(
                f"[SCOPE-001] '{tool}' not permitted. Allowed: {self._p['tool_allowlist']}"
            )

    def check_budget(self, actor: str, est_tokens: int) -> None:
        used = self._token_counts.get(self._today_key(actor), 0)
        budget = self._p["daily_token_budget"]
        if used + est_tokens > budget:
            raise PermissionError(f"[QUOTA-001] Daily budget {budget} exceeded (used {used}).")

    def _content_ok(self, text: str) -> tuple[bool, str]:
        low = text.lower()
        for phrase in self._p["prohibited_phrases"]:
            if phrase in low:
                return False, f"Prohibited phrase: '{phrase}'"
        if self._p["required_disclaimer"] not in low:
            return False, "Required risk disclaimer missing."
        return True, ""

    def _record(self, actor: str, client_ref: str, tool: str,
                content: str, tokens: int, decision: str, rule_id: str) -> AuditRecord:
        r = AuditRecord(
            actor=actor, client_ref=client_ref, tool=tool,
            content_hash="sha256:" + hashlib.sha256(content.encode()).hexdigest()[:24],
            tokens=tokens, policy_version=self._p["version"],
            decision=decision, rule_id=rule_id,
        )
        self._log.append(asdict(r))
        return r

    def submit_draft(
        self, actor: str, client_ref: str, draft: str, tokens: int
    ) -> AuditRecord:
        ok, reason = self._content_ok(draft)
        if not ok:
            self._record(actor, client_ref, "draft_email", draft, tokens, "deny", "CONTENT-001")
            raise ValueError(f"[CONTENT-001] {reason}")
        key = self._today_key(actor)
        self._token_counts[key] = self._token_counts.get(key, 0) + tokens
        return self._record(actor, client_ref, "draft_email", draft, tokens, "allow", "")

    @property
    def audit_trail(self) -> list[dict]:
        return list(self._log)


# --- Demo ---
if __name__ == "__main__":
    enforcer = FinancialPolicyEnforcer(FINANCIAL_POLICY)
    rm = "rm:james.chen@firm.com"
    client = "ACCT-4892"

    # Blocked: disallowed tool
    try:
        enforcer.check_tool(rm, "get_raw_trade_data")
    except PermissionError as e:
        print(e)

    # Compliant draft — accepted
    good = (
        "Dear Mr. Smith, We suggest a balanced fund allocation. "
        "Past performance is not indicative of future results."
    )
    try:
        enforcer.check_tool(rm, "draft_email")
        r = enforcer.submit_draft(rm, client, good, 420)
        print(f"Accepted. Hash: {r.content_hash}")
    except (PermissionError, ValueError) as e:
        print(e)

    # Non-compliant draft — blocked
    bad = "This guaranteed return fund will definitely increase your wealth."
    try:
        enforcer.submit_draft(rm, client, bad, 120)
    except ValueError as e:
        print(e)

    print(f"\nAudit trail ({len(enforcer.audit_trail)} records):")
    for rec in enforcer.audit_trail:
        print(f"  [{rec['decision'].upper()}] {rec['tool']} | rule={rec['rule_id'] or 'none'}")
